type ValidationSuccess = {
  valid: true;
  email: string;
  local: string;
  domain: string;
};

type ValidationFailure = {
  valid: false;
  email: string;
  error: string;
};

type ValidationResult = ValidationSuccess | ValidationFailure;

const EMAIL_REGEX = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?(?:\.[a-zA-Z0-9](?:[a-zA-Z0-9-]{0,61}[a-zA-Z0-9])?)*$/;

function validateEmail(email: string): ValidationResult {
  const trimmed = email.trim();

  if (trimmed.length === 0) {
    return { valid: false, email: trimmed, error: "Email is empty" };
  }

  if (trimmed.length > 254) {
    return { valid: false, email: trimmed, error: "Email exceeds 254 characters" };
  }

  const atIndex = trimmed.lastIndexOf("@");

  if (atIndex === -1) {
    return { valid: false, email: trimmed, error: "Missing @ symbol" };
  }

  const local = trimmed.slice(0, atIndex);
  const domain = trimmed.slice(atIndex + 1);

  if (local.length === 0) {
    return { valid: false, email: trimmed, error: "Local part is empty" };
  }

  if (local.length > 64) {
    return { valid: false, email: trimmed, error: "Local part exceeds 64 characters" };
  }

  if (domain.length === 0) {
    return { valid: false, email: trimmed, error: "Domain is empty" };
  }

  if (!domain.includes(".")) {
    return { valid: false, email: trimmed, error: "Domain must contain at least one dot" };
  }

  if (!EMAIL_REGEX.test(trimmed)) {
    return { valid: false, email: trimmed, error: "Invalid email format" };
  }

  return { valid: true, email: trimmed, local, domain };
}

export { validateEmail, ValidationResult, ValidationSuccess, ValidationFailure };
